import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.Crpw6aS5.js";const g=JSON.parse('{"title":"ROS2 节点因缺少 HOME 环境变量崩溃","description":"","frontmatter":{},"headers":[],"relativePath":"3 问题记录/ROS2节点因缺少HOME环境变量崩溃.md","filePath":"3 问题记录/ROS2节点因缺少HOME环境变量崩溃.md","lastUpdated":1784187140000}'),l={name:"3 问题记录/ROS2节点因缺少HOME环境变量崩溃.md"};function o(r,s,t,p,d,c){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="ros2-节点因缺少-home-环境变量崩溃" tabindex="-1">ROS2 节点因缺少 HOME 环境变量崩溃 <a class="header-anchor" href="#ros2-节点因缺少-home-环境变量崩溃" aria-label="Permalink to &quot;ROS2 节点因缺少 HOME 环境变量崩溃&quot;">​</a></h1> <h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2> <p>不设置 <code>HOME</code> 环境变量运行 ROS 2 节点，节点直接崩溃，无法启动。</p> <h2 id="根本原因" tabindex="-1">根本原因 <a class="header-anchor" href="#根本原因" aria-label="Permalink to &quot;根本原因&quot;">​</a></h2> <p>ROS 2 日志子系统初始化时需要确定日志目录，查找逻辑：</p> <ol><li><code>ROS_LOG_DIR</code> 非空 → 直接使用</li> <li>否则 → <code>$ROS_HOME/log</code></li> <li><code>ROS_HOME</code> 也未设置 → 回退到 <code>~/.ros</code></li></ol> <p>第 3 步中 <code>~</code> 的展开依赖 <code>HOME</code> 环境变量。<code>rcutils</code> 的 <code>rcutils_expand_user()</code> 在 <code>HOME</code> 不存在时直接失败，日志目录无法解析，抛出致命错误：</p> <div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rcutils_expand_user failed, at .../rcl_logging_interface/src/logging_dir.c:81</span></span>
<span class="line"><span>Failed to get logging directory, at .../rcl_logging_spdlog/src/rcl_logging_spdlog.cpp:84</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>节点在日志子系统初始化阶段就崩溃，还没执行任何业务逻辑。</p> <h2 id="受影响场景" tabindex="-1">受影响场景 <a class="header-anchor" href="#受影响场景" aria-label="Permalink to &quot;受影响场景&quot;">​</a></h2> <ul><li><strong>Docker 容器</strong>：部分最小化镜像不设置 <code>HOME</code></li> <li><strong>systemd 服务</strong>：默认不继承用户的 <code>HOME</code> 变量</li> <li><strong>Python subprocess</strong>：<code>subprocess.Popen</code> 启动的子进程可能缺少 <code>HOME</code></li></ul> <h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2> <p>任选其一：</p> <div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 方案 1：设置 HOME（最根本）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> HOME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/root</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 方案 2：设置 ROS_LOG_DIR 为绝对路径（绕过 ~ 展开）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ROS_LOG_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/tmp/ros_logs</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 方案 3：设置 ROS_HOME 为绝对路径（日志目录变为 $ROS_HOME/log）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ROS_HOME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/tmp/.ros</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>方案 2 和 3 <strong>不要使用 <code>~</code></strong>，否则只是把问题换了个地方。必须用绝对路径。</p> <h2 id="其他受影响的功能" tabindex="-1">其他受影响的功能 <a class="header-anchor" href="#其他受影响的功能" aria-label="Permalink to &quot;其他受影响的功能&quot;">​</a></h2> <p><code>~/.ros</code> 还被以下功能使用，<code>HOME</code> 缺失同样会导致问题：</p> <ul><li><strong>rosbag2</strong>：默认录制存储路径 <code>~/.ros/</code></li> <li><strong>SROS2 安全</strong>：默认密钥库路径 <code>~/.ros/</code></li> <li><strong>Fast-DDS</strong>：共享内存配置等也可能依赖 <code>HOME</code></li></ul>`,33)])])}const k=a(l,[["render",o]]);export{g as __pageData,k as default};
